class Solution:
    def maximumStrongPairXor(self, nums):
        arr = sorted(nums)
        n = len(arr)
        best = 0
        for i in range(n):
            for j in range(i, n):
                if arr[j] <= 2 * arr[i]:
                    best = max(best, arr[i] ^ arr[j])
                else:
                    break
        return best

