class Solution:
    def maximumStrongPairXor(self, nums):
        best = 0
        n = len(nums)
        for i in range(n):
            for j in range(n):
                x, y = nums[i], nums[j]
                if abs(x - y) <= min(x, y):
                    best = max(best, x ^ y)
        return best

