var maximumStrongPairXor = function(nums) {
    let best = 0;
    const n = nums.length;
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            const x = nums[i], y = nums[j];
            if (Math.abs(x - y) <= Math.min(x, y)) {
                best = Math.max(best, x ^ y);
            }
        }
    }
    return best;
};
